import com.alibaba.nacos.api.ai.model.mcp.registry.NacosMcpRegistryServerDetail;
import com.alibaba.nacos.api.ai.model.mcp.McpServerBasicInfo;
import com.fasterxml.jackson.databind.ObjectMapper;
import java.util.HashMap;
import java.util.Map;

public class test_security_schemes {
    public static void main(String[] args) {
        try {
            ObjectMapper mapper = new ObjectMapper();

            // Test 1: Check if securitySchemes field exists in McpRegistryServerDetail
            McpRegistryServerDetail detail = new McpRegistryServerDetail();
            detail.setId("test-id");
            detail.setName("test-server");

            // Try to set securitySchemes (this should fail initially)
            try {
                java.lang.reflect.Method setSecuritySchemes = detail.getClass().getMethod("setSecuritySchemes", Map.class);
                Map<String, Object> securitySchemes = new HashMap<>();
                securitySchemes.put("apiKey", Map.of("type", "apiKey", "name", "X-API-Key", "in", "header"));
                setSecuritySchemes.invoke(detail, securitySchemes);
                System.out.println("SUCCESS: securitySchemes field exists in McpRegistryServerDetail");
            } catch (NoSuchMethodException e) {
                System.out.println("FAIL: securitySchemes field does not exist in McpRegistryServerDetail");
            }

            // Test 2: Check if securitySchemes field exists in McpServerBasicInfo
            McpServerBasicInfo basicInfo = new McpServerBasicInfo();
            try {
                java.lang.reflect.Method setSecuritySchemes = basicInfo.getClass().getMethod("setSecuritySchemes", Map.class);
                Map<String, Object> securitySchemes = new HashMap<>();
                securitySchemes.put("apiKey", Map.of("type", "apiKey", "name", "X-API-Key", "in", "header"));
                setSecuritySchemes.invoke(basicInfo, securitySchemes);
                System.out.println("SUCCESS: securitySchemes field exists in McpServerBasicInfo");
            } catch (NoSuchMethodException e) {
                System.out.println("FAIL: securitySchemes field does not exist in McpServerBasicInfo");
            }

            // Test 3: Check serialization with securitySchemes
            String json = "{\"id\":\"test\",\"name\":\"test-server\",\"securitySchemes\":{\"apiKey\":{\"type\":\"apiKey\",\"name\":\"X-API-Key\",\"in\":\"header\"}}}";
            try {
                McpRegistryServerDetail deserialized = mapper.readValue(json, McpRegistryServerDetail.class);
                java.lang.reflect.Method getSecuritySchemes = deserialized.getClass().getMethod("getSecuritySchemes");
                Object schemes = getSecuritySchemes.invoke(deserialized);
                if (schemes != null) {
                    System.out.println("SUCCESS: securitySchemes can be deserialized from JSON");
                } else {
                    System.out.println("FAIL: securitySchemes deserialized as null");
                }
            } catch (Exception e) {
                System.out.println("FAIL: Cannot deserialize securitySchemes from JSON: " + e.getMessage());
            }

        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}

