        apiKeyScheme.put("in", "header");
        securitySchemes.put("apiKey", apiKeyScheme);
        detail.setSecuritySchemes(securitySchemes);

        assertNotNull(detail.getSecuritySchemes());
        assertEquals(1, detail.getSecuritySchemes().size());
        assertEquals(apiKeyScheme, detail.getSecuritySchemes().get("apiKey"));
    }

