/**
 * Integration test for securitySchemes support in MCP registry service.
 *
 * @author xinluo
 */
class SecuritySchemesIntegrationTest {

    @Mock
    private McpServerOperationService mcpServerOperationService;

    @Mock
    private NamespaceOperationService namespaceOperationService;

    @Mock
    private McpServerIndex mcpServerIndex;

    private NacosMcpRegistryService nacosMcpRegistryService;

    @BeforeEach
    void setUp() {
        MockitoAnnotations.openMocks(this);
        nacosMcpRegistryService = new NacosMcpRegistryService(
                mcpServerOperationService, namespaceOperationService, mcpServerIndex);
    }

    @Test
    void testGetServerWithSecuritySchemes() throws NacosException {
        // Setup test data
        String serverId = "test-server-id";
        String namespaceId = "test-namespace";

        McpServerIndexData indexData = new McpServerIndexData();
        indexData.setServerId(serverId);
        indexData.setNamespaceId(namespaceId);

        McpServerDetailInfo mcpServerDetailInfo = new McpServerDetailInfo();
